import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt3001.jpg",l="/images/lekt3002.jpg",n="/images/lekt3003.jpg",s="/images/lekt3005.jpg",o="/images/lekt3004.jpg",u="/images/lekt2904.jpg",f=JSON.parse('{"title":"Lektion 30","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion30.md","filePath":"lektionen/lektion30.md"}'),p={name:"lektionen/lektion30.md"};function h(b,t,m,c,k,g){return r(),d("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-30" tabindex="-1">Lektion 30 <a class="header-anchor" href="#lektion-30" aria-label="Permalink to &quot;Lektion 30&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>30.1. Die 9. Präsensklasse (क्र्यादि = &quot;क्री u.s.w.&quot;)</li><li>30.2. Gebrauch des Optativ (लिङ्)</li><li>30.3. Sekundärendungen der 3. Personen Singular und Plural</li><li>30.4. Bildung des Optativ Präsens (लिङ्) <ul><li>30.4.1. Thematische Präsensklassen</li><li>30.4.2. Athematische Präsensklassen</li></ul></li><li>30.5. Sandhi von auslautendem -r</li><li>30.6. Wortliste</li><li>30.7. Übung</li><li>30.8. Wiederholungsübung zur Formenlehre</li></ul><h2 id="_30-1-die-9-prasensklasse-क्र्यादि-क्री-u-s-w" tabindex="-1">30.1. Die 9. Präsensklasse (क्र्यादि = &quot;क्री u.s.w.&quot;) <a class="header-anchor" href="#_30-1-die-9-prasensklasse-क्र्यादि-क्री-u-s-w" aria-label="Permalink to &quot;30.1. Die 9. Präsensklasse (क्र्यादि = &quot;क्री u.s.w.&quot;)&quot;">​</a></h2><p>Bildung:</p><ul><li><p>starker Stamm: tiefstufige Wurzel + -nā-</p></li><li><p>schwacher Stamm:</p><ul><li><p>vor Konsonant: Tiefstufige Wurzel + -nī-</p></li><li><p>vor Vokal: tiefstufige Wurzel + -n-</p></li></ul></li></ul><p>Beispiel:</p><blockquote><p>क्री 9U &quot;kaufen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>क्रीणाति</td><td></td></tr><tr><td>(krī + nā + ti)</td><td>क्रीणन्ति</td><td></td></tr><tr><td>(krī + n + anti)</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>क्रीणीते</td><td></td></tr><tr><td>(krī + nī + te)</td><td>क्रीणते</td><td></td></tr><tr><td>(krī + n + ate)</td><td></td><td></td></tr></tbody></table></blockquote></blockquote><p>Bei dieser Präsensklasse ist besonders zu beachten die Bildung des Präsensstamms zur Wurzel ज्ञा 9U &quot;erkennen, wissen&quot;:</p><blockquote><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>जानाति</td><td></td></tr><tr><td>(jā-na-ti)</td><td>जानन्ति</td><td></td></tr><tr><td>(jā-n-anti)</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>जानीते</td><td></td></tr><tr><td>(jā-nī-te)</td><td>जानते</td><td></td></tr><tr><td>(jā-n-ate)</td><td></td><td></td></tr></tbody></table><p>Die Form जा die, dem Präsensstamm von ज्ञा zugrundeliegt, ist entweder durch eine Ablautreihe -ā (Tiefstufe) -nā (Hochstufe) zu erklären, oder durch Dissimilation aus *jñā-nā-ti.</p></blockquote><p>Einige Wurzeln auf langen Vokal verkürzen diesen vor dem Präsensstammsuffix der 9. Klasse:</p><p>Beispiel:</p><blockquote><p>पू 9U &quot;reinigen&quot;</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>पुनाति</td><td></td></tr><tr><td>(pu-nā-ti)</td><td>पुनन्ति</td><td></td></tr><tr><td>(pu-n-anti)</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>पुनीते</td><td></td></tr><tr><td>(pu-nī-te</td><td>पुनते</td><td></td></tr><tr><td>(pu-n-ate)</td><td></td><td></td></tr></tbody></table></blockquote><p>Bildung des Partizip Präsens Parasmaipada:</p><p>Beispiel:</p><blockquote><p>क्रीणन्त् (krī + n + ant) ; fem.: क्रीणती (krī + n + at + ī)</p></blockquote><h2 id="_30-2-gebrauch-des-optativ-लिङ्" tabindex="-1">30.2. Gebrauch des Optativ (लिङ्) <a class="header-anchor" href="#_30-2-gebrauch-des-optativ-लिङ्" aria-label="Permalink to &quot;30.2. Gebrauch des Optativ (लिङ्)&quot;">​</a></h2><p>Der Optativ wird gebraucht:</p><p>1. zur Bezeichnung</p><ul><li>eines Wunsches</li><li>einer Bitte</li><li>eines gemilderten Befehls</li></ul><p>(hierbei überschneidet sich der Optativ - लिङ् - mit dem Imperativ - लोट्)</p><p>Beispiel:</p><blockquote><p>दासो ग्राममागच्छेत् = &quot;Der Leibeigene möge ins Dorf kommen&quot;</p></blockquote><p>2. Wenn etwas als</p><ul><li>möglich</li><li>wahrscheinlich</li><li>vermutlich</li></ul><p>dargestellt werden soll.</p><p>Beispiel:</p><blockquote><p>ग्रामाच्चेद्गच्छेद्गुरुं न शृणुयात् = &quot;Wenn er aus dem Dorf ginge, würde er den Meister nicht hören&quot;</p></blockquote><p>3. Relativsätze mit Optativ haben manchmal die Bedeutung: &quot;Wenn jemand ...&quot;</p><p>Beispiel:</p><blockquote><p>यो नृतं वदेत्स नरकं पतेत् = &quot;Wenn jemand die Unwahrheit sagen würde, würde er in die Hölle fallen = Wenn jemand Unwahrheit sagt, fällt er in die Hölle&quot;</p></blockquote><h2 id="_30-3-sekundarendungen-der-3-personen-singular-und-plural" tabindex="-1">30.3. Sekundärendungen der 3. Personen Singular und Plural <a class="header-anchor" href="#_30-3-sekundarendungen-der-3-personen-singular-und-plural" aria-label="Permalink to &quot;30.3. Sekundärendungen der 3. Personen Singular und Plural&quot;">​</a></h2><p>Der Optativ (लिङ्), das Imperfekt (लङ्), der Aorist (लुङ्), Prekativ (आशिर्लिङ्) und Konditionalis haben die sog. Sekundärendungen:</p><table tabindex="0"><thead><tr><th></th><th>3. Person Singular</th><th>3. Person Plural</th></tr></thead><tbody><tr><td>Parasmaipada</td><td>-t</td><td>-n</td></tr><tr><td>athematische Klassen: -an oder -ur</td><td></td><td></td></tr><tr><td>Optativ: -ur</td><td></td><td></td></tr><tr><td>Ātmanepada</td><td>-ta</td><td>-nta</td></tr><tr><td>athematische Klassen: -ata (aus *nta)</td><td></td><td></td></tr><tr><td>Optativ: -ran</td><td></td><td></td></tr></tbody></table><h2 id="_30-4-bildung-des-optativ-prasens-लिङ्" tabindex="-1">30.4. Bildung des Optativ Präsens (लिङ्) <a class="header-anchor" href="#_30-4-bildung-des-optativ-prasens-लिङ्" aria-label="Permalink to &quot;30.4. Bildung des Optativ Präsens (लिङ्)&quot;">​</a></h2><h3 id="_30-4-1-thematische-prasensklassen" tabindex="-1">30.4.1. Thematische Präsensklassen <a class="header-anchor" href="#_30-4-1-thematische-prasensklassen" aria-label="Permalink to &quot;30.4.1. Thematische Präsensklassen&quot;">​</a></h3><p>vor konsonantische anlautenden Endungen:</p><p>Präsensstamm + -i- (das mit dem -a- zu -e- verschmilzt) + Sekundärendungen</p><p>vor vokalisch anlautenden Endungen:</p><p>Präsensstamm + -i- (» -e-) + -y- + Sekundärendung</p><p>Beispiele:</p><p>1. Präsensklasse:</p><blockquote><p>भू</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>भवेत्</td><td></td></tr><tr><td>bhava + i + t</td><td>भवेयुर्</td><td></td></tr><tr><td>bhava + i + y + ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>भवेत</td><td></td></tr><tr><td>bhava + i + ta</td><td>भवेरन्</td><td></td></tr><tr><td>bhava + i + ran</td><td></td><td></td></tr></tbody></table></blockquote><p>4. Präsensklasse:</p><blockquote><p>नृत्</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>नृत्येत्</td><td></td></tr><tr><td>nṛtya + i + t</td><td>नृत्येयुर्</td><td></td></tr><tr><td>nṛtya + i + y + ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>नृत्येत</td><td></td></tr><tr><td>nṛtya + i + ta</td><td>नृत्येरन्</td><td></td></tr><tr><td>nṛtya + i + ran</td><td></td><td></td></tr></tbody></table></blockquote><p>6. Präsensklasse</p><blockquote><p>विश्</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>विशेत्</td><td></td></tr><tr><td>viśa + i + t</td><td>विशेयुर्</td><td></td></tr><tr><td>viśa + i + y + ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>विशेत</td><td></td></tr><tr><td>viśa + i + ta</td><td>विशेरन्</td><td></td></tr><tr><td>viśa + i + ran</td><td></td><td></td></tr></tbody></table></blockquote><p>10. Präsensklasse und Kausative</p><blockquote><p>चुर्</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>चोरयेत्</td><td></td></tr><tr><td>coryaya + i +t</td><td>चोरयेयुर्</td><td></td></tr><tr><td>coraya + i + y + ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>चोरयेत</td><td></td></tr><tr><td>coraya + i + ta</td><td>चोरयेरन्</td><td></td></tr><tr><td>coraya + i + ran</td><td></td><td></td></tr></tbody></table></blockquote><h3 id="_30-4-2-athematische-prasensklassen" tabindex="-1">30.4.2. Athematische Präsensklassen <a class="header-anchor" href="#_30-4-2-athematische-prasensklassen" aria-label="Permalink to &quot;30.4.2. Athematische Präsensklassen&quot;">​</a></h3><p>Parasmaipada:</p><p>schwacher Präsensstamm + -yā- (vor -ur: -y-) + Sekundärendung</p><p>Ātmanepada:</p><p>schwacher Präsensstamm + -ī- + Sekundärendung</p><p>Beispiele:</p><p>2. Präsensklasse:</p><blockquote><p>द्विष्</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>द्विष्यात्</td><td></td></tr><tr><td>dviṣ-yā-t</td><td>द्विष्युर्</td><td></td></tr><tr><td>dviṣ-y-ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>द्विषीत</td><td></td></tr><tr><td>dviṣ-ī-ta</td><td>द्विषीरन्</td><td></td></tr><tr><td>dviṣ-ī-ran</td><td></td><td></td></tr></tbody></table></blockquote><p>5. Präsensklasse</p><blockquote><p>सु</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>सुनुयात्</td><td></td></tr><tr><td>sunu-yā-t</td><td>सुनुयुर्</td><td></td></tr><tr><td>sunu-y-ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>सुन्वीत</td><td></td></tr><tr><td>sunu + ī + ta</td><td>सुन्वीरन्</td><td></td></tr><tr><td>sunu + ī + ran</td><td></td><td></td></tr></tbody></table></blockquote><p>8. Präsensklasse</p><blockquote><p>तन्</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>तनुयात्</td><td></td></tr><tr><td>tanu-yā-t</td><td>तनुयुर्</td><td></td></tr><tr><td>tanu-y-ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>तन्वीत</td><td></td></tr><tr><td>tanu + ī + ta</td><td>तन्वीरन्</td><td></td></tr><tr><td>tanu + ī + ran</td><td></td><td></td></tr></tbody></table><p>कृ</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>कुर्यात्</td><td>कुर्युर्</td></tr><tr><td>3. Person Ātmanepada</td><td>कुर्वीत</td><td>कुर्वीरन्</td></tr></tbody></table></blockquote><p>9. Präsensklasse</p><blockquote><p>क्री</p><table tabindex="0"><thead><tr><th></th><th>Singular</th><th>Plural</th></tr></thead><tbody><tr><td>3. Person Parasmaipada</td><td>क्रीणीयात्</td><td></td></tr><tr><td>krīṇī-yā-t</td><td>क्रीणीयुर्</td><td></td></tr><tr><td>krīṇī-y-ur</td><td></td><td></td></tr><tr><td>3. Person Ātmanepada</td><td>क्रीणीत</td><td></td></tr><tr><td>krīṇ-ī-ta</td><td>क्रीणीरन्</td><td></td></tr><tr><td>krīṇ-ī-ran</td><td></td><td></td></tr></tbody></table></blockquote><h2 id="_30-5-sandhi-von-auslautendem-r" tabindex="-1">30.5. Sandhi von auslautendem -r <a class="header-anchor" href="#_30-5-sandhi-von-auslautendem-r" aria-label="Permalink to &quot;30.5. Sandhi von auslautendem -r&quot;">​</a></h2><p>Außer für -ar gelten für auslautendes -r dieselben Sandhiregeln wie für auslautendes -s.</p><p>-ar vor tönenden Lauten bleibt -ar, vor r- aber fällt das -r aus und das -a- wird durch -ā- ersetzt.</p><p>Beispiele:</p><blockquote><p>भवेयुर् + च » भवेयुश्च</p><p>पुनर् + अग्निः » पुनरग्निः</p><p>पुनर् +  रोदिति » पुना रोदिति</p></blockquote><h2 id="_30-6-wortliste" tabindex="-1">30.6. Wortliste <a class="header-anchor" href="#_30-6-wortliste" aria-label="Permalink to &quot;30.6. Wortliste&quot;">​</a></h2><p>क्री 9U क्रीणाति : kaufen</p><blockquote><p>Fut. क्रेष्यति<br> Pass. क्रीयते<br> PPP क्रीत<br> Inf. क्रेतुम्</p></blockquote><p>क्री + वि 9Ā विक्रीणीते : verkaufen</p><blockquote><p>Absol. विक्रीय</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: क्रीणन्ति विक्रीनते च<br> Bundi = बुन्दी, Rajasthan = राजस्थान<br> [Bildquelle: earth2marsh. -- <a href="http://www.flickr.com/photos/earth2marsh/56270619/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/earth2marsh/56270619/</a>. -- Zugriff am 2008-12-21. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>ज्ञा 9U जानाति : kennen, erkennen, wissen, verstehen</p><blockquote><p>Fut. ज्ञास्यति<br> Pass.ज्ञायते<br> Kaus. ज्ञापयति</p><blockquote><p>Kaus. PPP ज्ञप्त / ज्ञापित</p></blockquote><p>PPP ज्ञात<br> Inf. ज्ञातुम्</p><p>davon:</p><p>ज्ञाति m.: (Bluts-)Verwandter (Verwandte sind diejenigen, die man kennt!)</p><p>ज्ञान n.: Erkenntnis, Wissen, Erkennen (bes. der &quot;höheren&quot; Wahrheiten in Religion und Philosophie)</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: ज्ञातयः<br> Darewadi, Ahmed Nagar District = अहमदनगर, Maharashtra = महाराष्ट्र<br> [Bildquelle: Robin Murphy / World Resources Institute. -- <a href="http://www.flickr.com/photos/worldresourcesinstitute/2555776315/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldresourcesinstitute/2555776315/</a>. -- Zugriff am 2008-12-21. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>पू 9U पुनाति : reinigen</p><blockquote><p>Fur. पविष्यति<br> Pass. पूयते<br> Kaus. पावयति<br> PPP पूत<br> Inf. पवितुम्</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: श्रोत्राणि पुनाति<br> [Bildquelle: Karmalize. -- <a href="http://www.flickr.com/photos/agaylon/1799930862/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/agaylon/1799930862/</a>. -- Zugriff am 2008-12-21. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p><p>अश् 9P अश्नाति : essen, verzehren</p><blockquote><p>Fut. अशिष्यति<br> Pass. अश्यते<br> Kaus. आशयति<br> PPP अशित<br> Inf. अशितुम्</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: अश्नीयात्<br> थाली, Südindien<br> [Bildquelle: Matthew Winterburn. -- <a href="http://www.flickr.com/photos/bezoire/2330831734/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/bezoire/2330831734/</a>. -- Zugriff am 2008-12-21. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>प्रिय ३: lieb, liebend, freundlich</p><p><img src="'+o+'" alt=""><br> Abb.: प्रिया<br> [Bildquelle: Mary Wollstonecraft Shelley. -- <a href="http://www.flickr.com/photos/awflicks/3032833609/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/awflicks/3032833609/</a>. -- Zugriff am 2008-12-21. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p><p>चेत् Konjunktion: wenn; vorausgesetzt, dass (steht nie am Anfang eines Satzes)</p><blockquote><p>न चेत् : wenn nicht</p></blockquote><p>यदि Konjunktion: wenn</p><blockquote><p>यद्यपि : wenn auch, selbst wenn, obgleich</p><p>यद्येवम् : wenn es so ist, unter diesen Umständen</p></blockquote><p>पुनर् : wieder, immer wieder, zurück, noch einmal, dagegen, aber</p><blockquote><p>पुनः पुनर् : immer wieder</p><p>davon:</p><p>पुनर्भव m.: Wiedergeburt</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: पुनर्भवः<br> [Bildquelle: Wikipedia / Copyrighted to Himalayan Academy Publications, Kapaa, Kauai, Hawaii. -- <a href="http://en.wikipedia.org/wiki/Creative_Commons" title="w:Creative Commons" target="_blank" rel="noreferrer">Creative Commons</a> <a href="http://creativecommons.org/licenses/by-sa/2.5/" title="http://creativecommons.org/licenses/by-sa/2.5/" target="_blank" rel="noreferrer">Attribution ShareAlike 2.5</a>]</p><p>जीव् 1P जीवति : leben</p><blockquote><p>Fut. जीविष्यति<br> Pass. जीव्यते<br> Kaus. जीवयति<br> PPP जीवित : lebend<br> Inf. जीवितुम्</p><p>davon:</p><p>जीव m./n.: Leben, individuelle Seele</p></blockquote><p>सनातन ३ fem.: सनातनी : ewig, unvergänglich, beständig</p><h2 id="_30-7-ubung" tabindex="-1">30.7. Übung <a class="header-anchor" href="#_30-7-ubung" aria-label="Permalink to &quot;30.7. Übung&quot;">​</a></h2><p>A) Wandeln Sie folgende Verbalformen in die in Person, Zahl und Genus verbi entsprechende Optativformen um:</p><ol><li>ह्रियते</li><li>ध्नन्ति</li><li>स्मरति</li><li>स्थापयन्ति</li><li>स्तौति</li><li>सर्ज्यते</li><li>सुन्वन्ति</li><li>सिञ्चति</li><li>शृणोति</li><li>शक्नुवन्ति</li><li>वर्तन्ते</li><li>वेशयन्ति</li><li>वस्ते</li><li>उष्यते</li><li>वाद्यते</li><li>उच्यते</li><li>लम्भ्यते</li><li>रक्षयन्ति</li><li>युध्यते</li><li>इज्यते</li><li>म्रियते</li><li>मुञ्चन्ति</li><li>मन्यन्ते</li><li>भवति</li><li>भजन्ति</li><li>ब्रवीति</li><li>बुध्यते</li><li>पृच्छन्ति</li><li>पुनाति</li><li>पाति</li><li>पीयते</li><li>पद्यते</li><li>पतति</li><li>पाचयन्ति</li><li>नृत्यन्ति</li><li>नीयते</li><li>द्विषते</li><li>पश्यन्ति</li><li>दोग्धि</li><li>दुष्यति</li><li>देशयन्ति</li><li>दहति</li><li>तनुते</li><li>जानाति</li><li>जानते</li><li>जयन्ति</li><li>जायन्ते</li><li>चोर्यते</li><li>चारयति</li><li>गच्छन्ति</li><li>खाद्यते</li><li>क्रीणीते</li><li>क्रियते</li><li>कोपयति</li><li>कामयते</li><li>इच्छति</li><li>आययन्ति</li><li>आस्यते</li><li>आप्नुवते</li><li>अस्यते</li><li>सन्ति</li><li>अश्नुते</li><li>अर्हति</li><li>अदन्ति</li><li>अध्यापयन्ति</li></ol><p>B) Überrsetzen Sie die folgenden Sätze und lösen Sie die Komposita auf Sanskrit auf:</p><p>जना आर्यसत्यानि जानीयुरिति सुगतेनार्याणां सुखाय जना धर्मं ज्ञाप्यन्ते ॥१॥</p><p>ये नरा देवान्न यजेरन्व्रतानि च न चरेयुरनृतं च वदेयुरधर्मं च कुर्युस्ते स्सुखं नाप्नुयुर्मृत्वा च नरकं पतेयुः ॥२॥</p><p>ज्ञातिरागच्छेतितीष्ट्वार्यपुत्रो ज्ञातिं दासमाययति ॥३॥</p><p>अन्नलोभाद्दुःखं जायेतेति प्राप्तज्ञानः सुफलानि नाश्नाति ॥४॥</p><p>क्रयेण च विक्रयेण च वैश्या जीवेयुरिति वैश्यधर्मः । एवं सति वैश्यपुत्राः क्रीणन्ति विक्रीणते च ॥५॥</p><p>कृतपापो नरश्चेन्नरके पापात्पूतः स्यात्पुनर्भवं गच्छेत् ॥६॥</p><p>ब्राह्मणपुत्रा वेदाध्यायांश्च स्मृत्यध्यायांश्च पुनः पुनरधीयीरन्नित्यार्यधर्मः ॥७॥</p><p>यो ब्राह्मणः शूद्रां कामयेत स सद्ब्राह्मणो न स्यात् । सद्ब्राह्मणो हि ब्राह्मणीं कामयेत ॥८॥</p><p>सत्यं ब्रूयात्प्रियं ब्रूयान्न ब्रूयात्सत्यमप्रियम् ।<br> प्रियं च नानृतं ब्रूयादेष धर्मः सनातनः ॥९॥ ॥मनुस्मृति ४.१३८॥</p><h2 id="_30-8-wiederholungsubung-zur-formenlehre" tabindex="-1">30.8. Wiederholungsübung zur Formenlehre <a class="header-anchor" href="#_30-8-wiederholungsubung-zur-formenlehre" aria-label="Permalink to &quot;30.8. Wiederholungsübung zur Formenlehre&quot;">​</a></h2><p>Bestimmen und übersetzen Sie folgende Wortformen:</p><ol><li>भारे</li><li>अध्ययनम्</li><li>वस्तुतस्</li><li>वस्त्राणि</li><li>प्रतिमया</li><li>आचाराय</li><li>आचार्यैः</li><li>अश्वेषु</li><li>ताम्</li><li>वृत्त्यै</li><li>चरितस्य</li><li>अर्हता</li><li>शक्तीः</li><li>कामम्</li><li>भिक्षवे</li><li>भगवद्गीतायाम्</li><li>भगवति</li><li>भक्त्याः</li><li>स्थानात्</li><li>स्थित्या</li><li>मात्रायै</li><li>प्रभृतौ</li><li>हस्तेन</li><li>आदेः</li><li>दिष्टिम्</li><li>रुद्रः</li><li>मृत्यौ</li><li>मृतिः</li><li>द्विजातये</li><li>जातिभिः</li><li>व्वाघ्रान्</li><li>पूजाः</li><li>शत्रोः</li><li>उक्तिभ्यः</li><li>महान्ति</li><li>महति</li><li>सा</li><li>तस्यै</li><li>तस्मिन्</li><li>सते</li></ol>',112)])])}const q=e(p,[["render",h]]);export{f as __pageData,q as default};
